import React from 'react';
import './CommandeList.css';

const formatDate = (dateString) => {
  const options = { year: 'numeric', month: '2-digit', day: '2-digit' };
  return new Date(dateString).toLocaleDateString(undefined, options);
};

const CommandeList = ({ commandes = [], onSelect }) => {
  return (
    <div>
      <h2>Liste des Commandes</h2>
      <table className="commande-table">
        <thead>
          <tr>
            <th>ID</th>
            <th>Client</th>
            <th>Article</th>
            <th>Quantité</th>
            <th>Date</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {
            commandes.map((commande) => (
              <tr key={commande.idCOM}>
                <td>{commande.idCOM}</td>
                <td>{commande.codeCli} </td>
                <td>{commande.codeArt}</td>
                <td>{commande.QteCom}</td>
                <td>{formatDate(commande.dateCom)}</td>
                <td>
                  <button onClick={() => onSelect(commande)}>
                    Modifier / Supprimer
                  </button>
                </td>
              </tr>
            ))}
        </tbody>
      </table>
    </div>
  );
};

export default CommandeList;
